qry:select.qry:xquery:
for $r in SQL(' select WF.c_wf, WF.d_wf, count(INS.oi_instance) as cantidad from wrk02_instances as INS, wrk01_wf as WF, wrk05_organigramas as ORG_O, wrk05_organigramas as ORG_P,
wrk05_estructura as EST, wrk05_estructura as EST_CC, wrk05_estr_estr as EST_C, wrk05_entidad_estr as PER where INS.oi_wf=WF.oi_wf and INS.c_estructura=EST_C.c_estructura and WF.oi_organigrama=ORG_O.oi_organigrama and PER.oi_estructura=EST.oi_estructura and EST_C.oi_estructura=EST.oi_estructura and EST_C.c_estructura=EST_CC.c_estructura and ORG_P.oi_organigrama=EST_CC.oi_organigrama and ORG_P.oi_organigrama=EST.oi_organigrama and ORG_P.c_organigrama=ORG_O.c_organigrama and ORG_P.e_version=ORG_O.e_version_pub and ORG_O.l_automatica=0 and EST_C.e_deep>0 and INS.l_debug = {$CONSOLA/@debug} and PER.oi_entidad={$CONSOLA/@ETTY} group by WF.c_wf, WF.d_wf order by d_wf asc
')/ROWS/ROW

head.script:
						var SelectedMODE="TASK";

function amp()
{
return String.fromCharCode(38);
}

var crcCarpeta;       
var crcTitulo;
function eventClickOnPath(obj) 
{ 
ClickOnPath(obj.getAttribute("nmd-mode"), obj.getAttribute("nmd-idx")); 
if (obj.getAttribute("nmd-mode")!="WF")
parent.RefreshTitle(obj.getAttribute("nmd-mode"), "",crcTitulo);
}
function ClickOnPath(mode, idx)
{
var t,i;
var obj,aux;
var modes="TASK|OWNER|OWNER_CHILD|ADMIN|WF".split("|");

for (t=0; t!=modes.length; t++)
{
if (modes[t]==mode) 
{
   		obj=document.getElementsByName("PATH_"+modes[t]+"_TH");
   		aux=document.getElementsByName("PATH_"+modes[t]);
   		if (obj)
   		{     
obj[0].innerHTML=obj[0].innerHTML+" - Cargando...";   


switch(modes[t])
{
   case "TASK":
   		crcCarpeta = document.getElementById("AUX_IFRAME").getAttribute("crcTask");
   		crcTitulo = document.getElementById("AUX_IFRAME").getAttribute("crcTaskTitulo");
   		break;
   	case "OWNER":
   		crcCarpeta = document.getElementById("AUX_IFRAME").getAttribute("crcOwner");
   		crcTitulo = document.getElementById("AUX_IFRAME").getAttribute("crcOwnerTitulo");
   		break;
   	case "OWNER_CHILD":
   		crcCarpeta = document.getElementById("AUX_IFRAME").getAttribute("crcOwnerChild");
   		crcTitulo = document.getElementById("AUX_IFRAME").getAttribute("crcOwnerChildTitulo");
   		break;
   	case "ADMIN":
   		crcCarpeta = document.getElementById("AUX_IFRAME").getAttribute("crcAdmin");
   		crcTitulo = document.getElementById("AUX_IFRAME").getAttribute("crcAdminTitulo");
   		break;
   	case "WF":
   		crcCarpeta = document.getElementById("AUX_IFRAME").getAttribute("crcWf");        
   		crcTitulo = document.getElementById("AUX_IFRAME").getAttribute("crcWfTitulo");
   		break;
}

document.getElementById("AUX_IFRAME").src="ReportViewer.aspx?ut="+document.getElementById("AUX_IFRAME").getAttribute("nmd-ut")+amp()+"debug="+document.getElementById("AUX_IFRAME").getAttribute("nmd-debug")+amp()+"debugetty="+document.getElementById("AUX_IFRAME").getAttribute("nmd-etty")+amp()+"file=NucleusWF.Base.Ejecucion.ConsolaCarpetas.rpt"+amp()+"mode="+modes[t]+amp()+"crc="+crcCarpeta;
}
}	else 
{
   		aux=document.getElementsByName("PATH_"+modes[t]);
if (aux) 
for(i=0; i!=aux.length; i++)
aux[i].style.display="none";
}
}
}          
function Refresh() { ClickOnPath(SelectedMODE); }
function AutoRefresh() { ClickOnPath(SelectedMODE); window.setTimeout("AutoRefresh();",60000); }



function eventClickOnWF(obj)
{
parent.IniciarWF(obj.getAttribute("nmd-oiwf"));
}          

function eventClickOnTask(obj)
{
parent.RefreshTitle("TASK", obj.getAttribute("nmd-wfclass"),document.getElementById("AUX_IFRAME").getAttribute("crcTaskTitulo"));
}          

function eventClickOnOwner(obj)
{
parent.RefreshTitle("OWNER", obj.getAttribute("nmd-wfclass"),document.getElementById("AUX_IFRAME").getAttribute("crcOwnerTitulo"));
}          

function eventClickOnAdmin(obj)
{
parent.RefreshTitle("ADMIN", obj.getAttribute("nmd-wfclass"),document.getElementById("AUX_IFRAME").getAttribute("crcAdminTitulo"));
}

function eventClickOnOwnerChild(obj)
{
parent.RefreshTitle("OWNER_CHILD", obj.getAttribute("nmd-wfclass"),document.getElementById("AUX_IFRAME").getAttribute("crcOwnerChildTitulo"));
}          

function SetPathHTML(mode, txt)
{
var obj;
var aux;

//Arreglo el Titulo
obj=document.getElementById("PATH_"+mode+"_TH");
aux=""+obj.innerHTML; aux=aux.split("-")[0]; 
while(aux.substr(aux.length-1)==" ") aux=aux.substr(0,aux.length-1);
obj.innerHTML=aux;

//Agrego el HTML
obj=document.getElementById("PATH_"+mode+"_TD");
obj.innerHTML=txt;

//Muestro el TR
obj=document.getElementById("PATH_"+mode);
obj.style.display="";

//SelectID
SelectedMODE=mode;
}

function HTMLOnLoad()
{
var mode=document.getElementById("AUX_IFRAME").getAttribute("nmd-mode");

//Actualizar
if (mode=="ALL") window.setTimeout("AutoRefresh();",60000);
            else parent.SetPathHTML(mode,""+document.getElementById("PATH_"+mode+"_TD").innerHTML);
}

